import com.fasterxml.jackson.annotation.JsonInclude;
import lombok.Getter;
import lombok.Setter;

@Setter
@Getter
public class EnigmaStatusDTO {
    public int totalRotors;
    public int totalReflectors;
    public int totalProcessedMessages;
    public String originalCodeCompact;
    public String currentRotorsPositionCompact;


    @JsonInclude(JsonInclude.Include.NON_NULL)
    public Object originalCode;
    @JsonInclude(JsonInclude.Include.NON_NULL)
    public Object currentRotorsPosition;
}

package patmal.course.enigma.console;

import com.fasterxml.jackson.annotation.JsonInclude;
import lombok.Getter;
import lombok.Setter;

@Setter
@Getter
public class EnigmaStatusDTO {
    public int totalRotors;
    public int totalReflectors;
    public int totalProcessedMessages;
    public String originalCodeCompact;
    public String currentRotorsPositionCompact;


    @JsonInclude(JsonInclude.Include.NON_NULL)
    public Object originalCode;
    @JsonInclude(JsonInclude.Include.NON_NULL)
    public Object currentRotorsPosition;
}

package patmal.course.enigma.controllers;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;
import patmal.course.enigma.storage.MachineManager;


import patmal.course.enigma.storage.StorageManager;

@RestController
@RequestMapping("/enigma/config")
public class ConfigController {

    private final MachineManager machineManager;

    @Autowired
    public ConfigController(MachineManager machineManager) {
        this.machineManager = machineManager;
    }

    public ResponseEntity<?> getMachineStatus(
            @RequestParam(value = "verbose", defaultValue = "false") boolean verbose) {
        try {
            // קריאה למתודה דרך המופע המוזרק ולא בצורה סטטית
            return ResponseEntity.ok(machineManager.getMachineStatus());
        } catch (IllegalStateException e) {
            return ResponseEntity.badRequest().body(e.getMessage());
        }
    }

}

package patmal.course.enigma.controllers;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;
import patmal.course.enigma.console.MachineManager;

@RestController
@RequestMapping("/enigma/config")
public class ConfigController {

    private final MachineManager machineManager;

    @Autowired
    public ConfigController(MachineManager machineManager) {
        this.machineManager = machineManager;
    }

    @GetMapping("/status")
    public ResponseEntity<?> getMachineStatus(
            @RequestParam(value = "verbose", defaultValue = "false") boolean verbose) {
        try {
            // קריאה למתודה דרך המופע המוזרק ולא בצורה סטטית
            return ResponseEntity.ok(machineManager.getMachineStatus());
        } catch (IllegalStateException e) {
            return ResponseEntity.badRequest().body(e.getMessage());
        }
    }

}
